const keywords = JSON.parse($vars.REDDIT_MONITOR_KEYWORDS);
const settings = JSON.parse($vars.REDDIT_MONITOR_SETTINGS);
const apiKey = $vars.PERPLEXITY_API_KEY;
const baseUrl = $vars.FIRECRAWL_BASE_URL || 'https://api.firecrawl.dev/v2';
const staticData = $getWorkflowStaticData('global');
const seenUrls = staticData.seenUrls || {};
const now = new Date().toISOString();
const allPosts = [];
let totalScanned = 0;
const errors = [];
let retriesUsed = 0;
const scoring = { ht: 6, mt: 3, intent: ['looking for','recommend','alternative','switch from','better than','anyone use','comparison'], comps: ['apollo','instantly','clay','smartlead','lemlist','woodpecker','mailshake','outreach'] };
async function searchWithRetry(query, maxRetries = 3) {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await this.helpers.httpRequest({ method: 'POST', url: `${baseUrl}/search`, headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' }, body: { query, limit: 10, tbs: 'qdr:d', country: 'US' }, json: true });
      return response;
    } catch (err) { if (attempt < maxRetries) { retriesUsed++; await new Promise(r => setTimeout(r, Math.min(1000*Math.pow(2,attempt-1),8000))); continue; } throw err; }
  }
}
for (let i = 0; i < keywords.length; i++) {
  const kw = keywords[i];
  try {
    const response = await searchWithRetry.call(this, `${kw.q} site:reddit.com`);
    const webResults = response?.data?.web || response?.data || [];
    totalScanned += Array.isArray(webResults) ? webResults.length : 0;
    if (Array.isArray(webResults)) {
      for (const result of webResults) {
        const url = result.url || '';
        if (!url.includes('reddit.com') || seenUrls[url]) continue;
        let score = kw.c === 'comp' ? 3 : kw.c === 'opp' ? 2 : 1;
        const text = `${result.title||''} ${result.description||''}`.toLowerCase();
        for (const intent of scoring.intent) { if (text.includes(intent)) { score += 2; break; } }
        for (const comp of scoring.comps) { if (text.includes(comp)) { score += 2; break; } }
        if (text.includes('?')) score += 1;
        if (text.includes('looking for') || text.includes('recommend')) score += 1;
        score = Math.min(score, 10);
        const subMatch = url.match(/reddit\.com\/r\/([^/]+)/);
        allPosts.push({ title: result.title||'No title', url, desc: (result.description||'').slice(0,200), sub: subMatch?subMatch[1]:'unknown', kw: kw.q, cat: kw.c, score, label: score >= scoring.ht ? 'HIGH' : score >= scoring.mt ? 'MEDIUM' : 'LOW' });
        seenUrls[url] = now;
      }
    }
  } catch (err) { errors.push({ keyword: kw.q, error: err.message||String(err) }); }
  if (i < keywords.length - 1) await new Promise(r => setTimeout(r, 2000));
}
const cutoff = new Date(Date.now() - 30*24*60*60*1000).toISOString();
for (const [url, date] of Object.entries(seenUrls)) { if (date < cutoff) delete seenUrls[url]; }
staticData.seenUrls = seenUrls;
allPosts.sort((a, b) => b.score - a.score);
const high = allPosts.filter(p => p.label === 'HIGH');
const medium = allPosts.filter(p => p.label === 'MEDIUM');
return [{ json: { totalScanned, totalMatched: allPosts.length, highCount: high.length, mediumCount: medium.length, lowCount: allPosts.filter(p => p.label === 'LOW').length, highPosts: high, mediumPosts: medium, errors, retriesUsed, cacheSize: Object.keys(seenUrls).length, timestamp: now, hasResults: high.length > 0 || medium.length > 0, tenant_id: settings.tenant_id || 'ascend_gtm', keywordsProcessed: keywords.length } }];

const data = $json;
const high = data.highPosts || [];
const medium = data.mediumPosts || [];
const dateStr = new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' });
const blocks = [];
blocks.push({ type:'header', text:{type:'plain_text',text:'Reddit Intelligence Digest',emoji:true} });
blocks.push({ type:'context', elements:[{type:'mrkdwn',text:`:calendar: ${dateStr}  |  ${data.totalScanned} posts scanned  |  ${data.totalMatched} matched`}] });
blocks.push({ type:'divider' });
if (high.length > 0) {
  blocks.push({ type:'section', text:{type:'mrkdwn',text:`:fire: *Hot Opportunities (${high.length})*`} });
  for (const p of high.slice(0, 8)) {
    const snippet = p.desc ? p.desc.slice(0,140) + '...' : '';
    blocks.push({ type:'section', text:{type:'mrkdwn',text:`<${p.url}|${p.title}>\nr/${p.sub}  |  Score: ${p.score}/10  |  Match: _${p.kw}_\n${snippet}`} });
  }
  blocks.push({ type:'divider' });
}
if (medium.length > 0) {
  blocks.push({ type:'section', text:{type:'mrkdwn',text:`:eyes: *Worth Watching (${medium.length})*`} });
  const medText = medium.slice(0,8).map(p => `- <${p.url}|${p.title}> (r/${p.sub}, score ${p.score}/10, _${p.kw}_)`).join('\n');
  blocks.push({ type:'section', text:{type:'mrkdwn',text:medText} });
  blocks.push({ type:'divider' });
}
const subCounts = {};
for (const p of [...high, ...medium]) { subCounts[p.sub] = (subCounts[p.sub]||0)+1; }
const topSubs = Object.entries(subCounts).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([s,c])=>`r/${s} (${c})`).join(', ');
let statsText = `Posts scanned: ${data.totalScanned} | Matched: ${data.totalMatched} | High: ${data.highCount}`;
if (topSubs) statsText += `\nTop subreddits: ${topSubs}`;
if (data.errors && data.errors.length > 0) statsText += `\n:warning: ${data.errors.length} search(es) failed`;
blocks.push({ type:'context', elements:[{type:'mrkdwn',text:statsText}] });
blocks.push({ type:'context', elements:[{type:'mrkdwn',text:'_Ascend GTM  |  Reddit Intelligence  |  Daily 8 AM ET_'}] });
const fallback = `Reddit Intel: ${high.length} hot opportunities, ${medium.length} worth watching from ${data.totalScanned} posts`;
return [{ json: { blocks: blocks.slice(0,49), text: fallback, searchData: data } }];
